import { beforeEach, describe, expect, it, vi } from "vitest";
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
const mockWriteActiveStudioSession = vi.fn();
const mockUpdateActiveStudioSession = vi.fn();
const mockNavigateStudioAndAwaitAck = vi.fn().mockResolvedValue({ acked: true });
const mockFetchStreamTip = vi.fn().mockResolvedValue("tip-1");
const mockPollAgentSessionEvents = vi
    .fn()
    .mockReturnValue(new Promise(() => { }));
const mockCreateStudioSession = vi.fn().mockResolvedValue({
    sessionId: "new-session",
    serviceUrl: "https://test.invalid",
});
const mockOpenChromelessWindow = vi.fn().mockReturnValue(4242);
vi.mock("./activeStudioSession.js", () => ({
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
    writeActiveStudioSession: (...args) => mockWriteActiveStudioSession(...args),
    updateActiveStudioSession: (...args) => mockUpdateActiveStudioSession(...args),
}));
vi.mock("./agentSessionChannel.js", () => ({
    fetchStreamTip: (...args) => mockFetchStreamTip(...args),
    navigateStudioAndAwaitAck: (...args) => mockNavigateStudioAndAwaitAck(...args),
    pollAgentSessionEvents: (...args) => mockPollAgentSessionEvents(...args),
}));
vi.mock("./commands/createStudioSession.js", () => ({
    createStudioSession: (...args) => mockCreateStudioSession(...args),
}));
const mockCloseStudioWindowsBySession = vi.fn();
vi.mock("./browser.js", () => ({
    openChromelessWindow: (...args) => mockOpenChromelessWindow(...args),
    closeStudioWindowsBySession: (...args) => mockCloseStudioWindowsBySession(...args),
}));
vi.mock("./agentSessionKey.js", () => ({
    resolveAgentSessionKey: vi.fn().mockReturnValue("test-key"),
}));
vi.mock("./daemon/index.js", () => ({
    DaemonClient: vi.fn(),
    resolveAgentSessionKey: vi.fn().mockReturnValue("test-key"),
    resolveDaemonPaths: vi.fn(() => ({
        socketPath: "/tmp/test-daemon.sock",
        pidPath: "/tmp/test-daemon.pid",
        metaPath: null,
        worktreeRoot: null,
    })),
}));
const mockTruncateStudioEventLog = vi.fn();
vi.mock("./studioEventLog.js", async (importActual) => {
    const actual = await importActual();
    return {
        ...actual,
        truncateStudioEventLog: (...args) => mockTruncateStudioEventLog(...args),
    };
});
import { DaemonUnavailableError, StudioNavigationError } from "./errors.js";
import { DirectChannel, resolveChannel } from "./studioChannel.js";
beforeEach(() => {
    vi.clearAllMocks();
});
describe("DirectChannel", () => {
    it("creates a new session when no active session exists", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            serviceUrl: "https://test.invalid",
            apiKey: "key-1",
            initialPath: "/studio",
        }));
    });
    it("navigates an existing session when one is recorded", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/traces");
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("existing-session");
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "existing-session" }), "/studio/traces");
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
        // The pointer's currentPath tracks the navigation, matching the daemon path.
        expect(mockUpdateActiveStudioSession).toHaveBeenCalledWith({
            currentPath: "/studio/traces",
        });
    });
    it("throws StudioNavigationError when navigation is not acked", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await expect(channel.openOrNavigate("/studio")).rejects.toThrow(StudioNavigationError);
    });
    it("passes staleSessionId in navigation error", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "stale-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        try {
            await channel.openOrNavigate("/studio");
        }
        catch (err) {
            expect(err).toBeInstanceOf(StudioNavigationError);
            expect(err.staleSessionId).toBe("stale-session");
        }
    });
    it("subscribe calls fetchStreamTip before polling", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const onEvent = vi.fn();
        const onError = vi.fn();
        const sub = channel.subscribe("session-1", onEvent, onError);
        for (let i = 0; i < 20; i++) {
            if (mockPollAgentSessionEvents.mock.calls.length > 0) {
                break;
            }
            await Promise.resolve();
        }
        expect(mockFetchStreamTip).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "session-1" }));
        expect(mockPollAgentSessionEvents).toHaveBeenCalledWith(expect.objectContaining({
            sessionId: "session-1",
            startCursor: "tip-1",
        }));
        sub.abort();
    });
    it("truncates the durable log on a fresh open", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await channel.openOrNavigate("/studio");
        expect(mockTruncateStudioEventLog).toHaveBeenCalledWith("test-key");
    });
    it("does not truncate the log when navigating an existing session", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            windowState: "open",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await channel.openOrNavigate("/studio/traces");
        expect(mockTruncateStudioEventLog).not.toHaveBeenCalled();
    });
    it("reuses the window when windowState is not closed", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            windowState: "open",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/traces");
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("existing-session");
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
    });
    it("creates a new session when windowState is closed", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "closed-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            windowState: "closed",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalled();
        expect(mockNavigateStudioAndAwaitAck).not.toHaveBeenCalled();
    });
    it("opens the browser directly for keyless sign-in (login)", async () => {
        const channel = new DirectChannel("", "https://test.invalid");
        const signInPath = "/studio/sign-in?redirect_url=%2Fstudio&session=login-session";
        const result = await channel.openOrNavigate(signInPath, {
            sessionId: "login-session",
        });
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("login-session");
        // Keyless login must not hit the authenticated session-creation path.
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
        expect(mockOpenChromelessWindow).toHaveBeenCalledWith(`https://test.invalid${signInPath}`);
        expect(mockWriteActiveStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            sessionId: "login-session",
            serviceUrl: "https://test.invalid",
            windowPid: 4242,
            // Pre-auth window: must be written unauthenticated, else the keyless
            // reuse gate (!authenticated) never matches the pointer it just wrote.
            authenticated: false,
        }));
    });
    it("reuses a live keyless window at the same destination", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-login",
            serviceUrl: "https://test.invalid",
            source: "direct",
            authenticated: false,
            windowState: "open",
            currentPath: "/studio/sign-in?session=existing-login",
        });
        const channel = new DirectChannel("", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/sign-in?session=new", {
            sessionId: "new",
        });
        // The token lands on the live window's session, so we return that id.
        expect(result).toEqual({ sessionId: "existing-login", opened: false });
        // No second window, and the active-session pointer is left intact: keyless
        // reuse never navigates, so it must not touch currentPath either.
        expect(mockOpenChromelessWindow).not.toHaveBeenCalled();
        expect(mockWriteActiveStudioSession).not.toHaveBeenCalled();
        expect(mockUpdateActiveStudioSession).not.toHaveBeenCalled();
    });
    it("spawns a fresh keyless window for a different destination", async () => {
        // Reuse never navigates, so a window opened for another route would strand
        // the user on the first login's redirect: a different destination spawns.
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-login",
            serviceUrl: "https://test.invalid",
            source: "direct",
            authenticated: false,
            windowState: "open",
            currentPath: "/studio/sign-in?session=existing-login",
        });
        const channel = new DirectChannel("", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/experiments?session=new", { sessionId: "new" });
        expect(result.opened).toBe(true);
        expect(mockOpenChromelessWindow).toHaveBeenCalledTimes(1);
    });
    it("spawns a keyless window when the live pointer is for another service", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-login",
            serviceUrl: "https://other.invalid",
            source: "direct",
            authenticated: false,
            windowState: "open",
            currentPath: "/studio/sign-in?session=existing-login",
        });
        const channel = new DirectChannel("", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/sign-in?session=new", {
            sessionId: "new",
        });
        expect(result.opened).toBe(true);
        expect(mockOpenChromelessWindow).toHaveBeenCalledTimes(1);
    });
    it("appends a session param for keyless opens that lack one", async () => {
        const channel = new DirectChannel("", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio", {
            sessionId: "login-session",
        });
        expect(result.opened).toBe(true);
        expect(mockOpenChromelessWindow).toHaveBeenCalledWith("https://test.invalid/studio?session=login-session");
    });
    it("forwards clientHeaders to createStudioSession", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await channel.openOrNavigate("/studio", {
            clientHeaders: { "x-custom": "value" },
        });
        expect(mockCreateStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            clientHeaders: { "x-custom": "value" },
        }));
    });
});
describe("resolveChannel", () => {
    it("returns DirectChannel when daemon is not enabled", async () => {
        const channel = await resolveChannel("key-1", "https://test.invalid");
        expect(channel).toBeInstanceOf(DirectChannel);
    });
    it("falls back to DirectChannel silently when the daemon is not packaged", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return {
                connect: vi
                    .fn()
                    .mockRejectedValue(new DaemonUnavailableError("daemon entry point not found: /x")),
                destroy: vi.fn(),
            };
        });
        const errorSpy = vi.spyOn(console, "error").mockImplementation(() => { });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("", "https://test.invalid");
        expect(channel).toBeInstanceOf(DirectChannel);
        expect(errorSpy).not.toHaveBeenCalled();
        vi.unstubAllEnvs();
        errorSpy.mockRestore();
    });
});
describe("withDirectFallback (via resolveChannel)", () => {
    it("falls back to DirectChannel when daemon openOrNavigate fails", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockRejectedValue(new Error("socket dead")),
            destroy: vi.fn(),
            detach: vi.fn().mockResolvedValue(undefined),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalled();
        vi.unstubAllEnvs();
    });
    it("forwards the event id and routes daemon disconnects to onError", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        let eventHandler;
        let disconnectHandler;
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                ok: true,
                sessionId: "s1",
                browserConnected: true,
                reconnected: false,
            }),
            destroy: vi.fn(),
            detach: vi.fn().mockResolvedValue(undefined),
            onEvent: vi.fn((h) => {
                eventHandler = h;
            }),
            onDisconnect: vi.fn((h) => {
                disconnectHandler = h;
            }),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        await channel.openOrNavigate("/studio");
        const onEvent = vi.fn();
        const onError = vi.fn();
        channel.subscribe("s1", onEvent, onError);
        eventHandler?.({
            id: "cursor-42",
            event: "studio:navigated",
            data: { path: "/studio/traces" },
        });
        expect(onEvent).toHaveBeenCalledWith(expect.objectContaining({ id: "cursor-42", type: "studio:navigated" }));
        const err = new Error("daemon connection closed");
        disconnectHandler?.(err);
        expect(onError).toHaveBeenCalledWith(err);
        vi.unstubAllEnvs();
    });
    it("does not fall back on StudioNavigationError", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                ok: true,
                sessionId: "s1",
                browserConnected: true,
                reconnected: true,
            }),
            navigate: vi.fn().mockResolvedValue({ acked: false, reason: "blocked" }),
            destroy: vi.fn(),
            detach: vi.fn().mockResolvedValue(undefined),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        await expect(channel.openOrNavigate("/studio")).rejects.toThrow(StudioNavigationError);
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
        vi.unstubAllEnvs();
    });
});
describe("forceCloseWindow", () => {
    const SID = "33333333-3333-4333-8333-333333333333";
    it("DirectChannel runs the AppleScript close for the session", () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        channel.forceCloseWindow(SID);
        expect(mockCloseStudioWindowsBySession).toHaveBeenCalledWith(SID);
    });
    it("DaemonChannel is a no-op (the daemon force-closes server-side)", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                sessionId: "s1",
                browserConnected: true,
                reconnected: false,
            }),
            navigate: vi.fn().mockResolvedValue({ acked: true }),
            close: vi.fn().mockResolvedValue(undefined),
            detach: vi.fn().mockResolvedValue(undefined),
            destroy: vi.fn(),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        channel.forceCloseWindow(SID);
        expect(mockCloseStudioWindowsBySession).not.toHaveBeenCalled();
        vi.unstubAllEnvs();
    });
});
describe("clearSession", () => {
    const SID = "44444444-4444-4444-8444-444444444444";
    it("DirectChannel is a no-op (holds no out-of-process state)", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await expect(channel.clearSession(SID)).resolves.toBeUndefined();
        // The window/pointer reap lives in the caller, not the channel.
        expect(mockCloseStudioWindowsBySession).not.toHaveBeenCalled();
    });
    it("DaemonChannel drops the daemon's in-memory entry via client.clear", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                sessionId: "s1",
                browserConnected: true,
                reconnected: false,
            }),
            navigate: vi.fn().mockResolvedValue({ acked: true }),
            close: vi.fn().mockResolvedValue(undefined),
            clear: vi.fn().mockResolvedValue(1),
            detach: vi.fn().mockResolvedValue(undefined),
            destroy: vi.fn(),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        await channel.clearSession(SID);
        expect(mockClient.clear).toHaveBeenCalledWith(SID);
        vi.unstubAllEnvs();
    });
    it("DaemonChannel.clearSession swallows a client.clear failure", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                sessionId: "s1",
                browserConnected: true,
                reconnected: false,
            }),
            navigate: vi.fn().mockResolvedValue({ acked: true }),
            close: vi.fn().mockResolvedValue(undefined),
            clear: vi.fn().mockRejectedValue(new Error("socket gone")),
            detach: vi.fn().mockResolvedValue(undefined),
            destroy: vi.fn(),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        await expect(channel.clearSession(SID)).resolves.toBeUndefined();
        vi.unstubAllEnvs();
    });
});
